solution_code:
#include <stdio.h>
#include <signal.h>
#include <unistd.h>

volatile sig_atomic_t g_count = 0;

void handler_sigusr1(int sig) {
    (void)sig;
    g_count++;
}

int install_handler(void) {
    struct sigaction sa;
    sa.sa_handler = handler_sigusr1;
    sigemptyset(&sa.sa_mask);
    sa.sa_flags = SA_RESTART;
    return sigaction(SIGUSR1, &sa, NULL) == 0 ? 0 : -1;
}

int main(void) {
    if (install_handler() != 0) return 1;
    kill(getpid(), SIGUSR1);
    printf("count=%d\n", (int)g_count);
    return 0;
}
